    for oi := 0; oi < n; oi++ {
        bestDelta := math.MaxFloat64
        bestAi := -1
        bestSavedState := Assign{}
        // Try existing non-empty assigns first (in original order), then remaining empty slots
        for ai := 0; ai < MAXASSIGNS; ai++ {
            assign := &dispatch.Assigns[ai]
            if ai >= dispatch.AssignsLen && ai != nextEmptyIdx {
                continue
            }
            // Skip truly empty beyond current length except our target empty slot
            if ai >= dispatch.AssignsLen && nextEmptyIdx < MAXASSIGNS {
                if ai != nextEmptyIdx {
                    continue
                }
            }
            saved := *assign
            ok := assign.AddShip(total_ship+oi, oris[oi], dess[oi])
            if ok {
                assign.GenRoute()
                if assign.Cost >= 0 {
