algorithm:
For each unassigned ship, evaluate insertion into all existing non-empty assigns plus one potential new empty assign using cost delta comparison, always committing the best feasible insertion, falling back to a new assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type InsertRecord struct {
		assignIdx int
		costDelta float64
		feasible  bool
	}
	availableIndices := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			availableIndices = append(availableIndices, i)
		}
	}
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		bestRecord := InsertRecord{-1, 0.0, false}
		allIndices := make([]int, len(availableIndices)+1)
		copy(allIndices, availableIndices)
		newAssignCandidate := -1
		if dispatch.AssignsLen < MAXASSIGNS {
			newAssignCandidate = dispatch.AssignsLen
			allIndices[len(availableIndices)] = newAssignCandidate
		}
		for _, idx := range allIndices {
			if idx < 0 || idx >= MAXASSIGNS {
				continue
			}
			isNewAssign := idx >= dispatch.AssignsLen
			savedState := struct{}{}
			if !isNewAssign {
				savedState = savedState
			}
			addOk := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if addOk {
				dispatch.Assigns[idx].GenRoute()
				oldCost := dispatch.AccumulatedCost
				if isNewAssign {
					oldCost = 0.0
				} else {
					oldCost = dispatch.AccumulatedCost
				}
				costAfterInsert := dispatch.Assigns[idx].Cost
				var costDelta float64
				if costAfterInsert >= 0 {
					if isNewAssign {
						costDelta = costAfterInsert
					} else {
						prevCost := 0.0
						for k := 0; k < len(availableIndices); k++ {
							if availableIndices[k] == idx {
								prevCost = dispatch.AccumulatedCost
								break
							}
						}
						costDelta = costAfterInsert
					}
					if !bestRecord.feasible || costDelta < bestRecord.costDelta {
